insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('e6bf14a5-4365-535e-08d1-ebab9e34d9db', 'As a portfolio reviewer, I want the app''s own roadmap visible as a groomed backlog on a kanban board so that the product practice is inspectable instead of claimed.', 'The Product tab holds user stories with acceptance criteria, effort estimates, and WSJF scores on a Backlog / Groomed / In progress / Done board. The app manages its own development from day one.', '[{"text":"Stories carry title, description, acceptance criteria, job size, WSJF score, and status","done":true},{"text":"Board shows Backlog, Groomed, In progress, and Done columns with tap-to-move","done":true},{"text":"A Later shelf holds v3 candidates without crowding the board","done":true},{"text":"Ships seeded with the real v2 backlog, not filler","done":true}]'::jsonb, 5, 3, 4, 5, 'done', false, (now() - interval '1 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('cee25fe1-5a0a-161d-27b5-765c2babdbf3', 'As a daily user, I want every ranked item to explain its score in named framework factors so that I can trust the ordering or fix the inputs.', 'Replace the v1 ad hoc points with a WSJF adaptation: cost of delay (deadline urgency, importance, unblock value) divided by job size, with a staleness multiplier that boosts long-untouched work. Staleness stays first-class; it is this product''s differentiator.', '[{"text":"Score = cost of delay divided by job size, times a staleness multiplier","done":true},{"text":"Every card lists each factor with its points in plain language","done":true},{"text":"FRAMEWORK.md documents the model, the weights, and the rationale","done":true},{"text":"Unit tests cover deadline, staleness, and blocking boundaries","done":true}]'::jsonb, 5, 4, 3, 3, 'done', false, (now() - interval '1 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('ba0cba2a-4e54-04a4-a964-4a30ad695b08', 'As a daily user, I want to see what an item blocks and what blocks it so that I can pick the work that unblocks the most.', 'A per-item dependency view rendered as a nested list, both directions. Blocked items stay out of the ready ranking; items that unblock open work get a boost that names what they free up.', '[{"text":"Item detail shows blocked-by and blocks as nested lists","done":true},{"text":"Blocked items never top the ready list","done":true},{"text":"The unblock factor names the work it would free up","done":true},{"text":"Readable at 390px with no graph rendering","done":true}]'::jsonb, 4, 2, 4, 2, 'done', false, (now() - interval '1 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('09c823b7-3851-0920-6bfd-aee6f9bf7c54', 'As a backlog owner, I want a groom-this action that drafts a raw capture into a user story with proposed criteria and a proposed score so that grooming takes a minute and stays under my control.', 'Raw captures get a drafted story: title in story form, description, acceptance criteria, and suggested WSJF inputs. The draft is a proposal to accept or edit; nothing auto-applies. Calls Anthropic through a Vercel serverless proxy, stubbed behind an env flag until the key is wired in a supervised session.', '[{"text":"Groom this appears on raw captures only","done":true},{"text":"Proposal covers story title, description, criteria, and score inputs","done":true},{"text":"Nothing changes without an explicit accept","done":true},{"text":"Works end to end with the API stubbed; no key in the client or the repo","done":true}]'::jsonb, 4, 2, 3, 5, 'done', false, (now() - interval '1 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('98bead0f-fa58-599f-b12d-de9b7ea22f14', 'As a portfolio reviewer, I want an About view explaining the product and how it was built so that the app doubles as its own case study.', 'One screen: what Foreground is, the prioritization framework it uses, and the build approach. Written as case study copy, reachable from the wordmark header on every screen.', '[{"text":"Covers the product, the framework, and the build in one screen","done":true},{"text":"Reachable in one tap from anywhere in the app","done":true},{"text":"Every screen is screenshot-safe: placeholder data only","done":true}]'::jsonb, 3, 2, 1, 1, 'done', false, (now() - interval '1 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('5c8c80c6-60c9-4d90-7899-2426cec906be', 'As the builder, I want the grooming proxy wired to the live Anthropic API in a supervised session so that drafts get model quality without a key ever entering the repo.', 'The serverless function and UI are complete and stubbed. Remaining work is Vercel env configuration and a supervised smoke test.', '[{"text":"Key lives only in Vercel project env, never in the repo or the client","done":false},{"text":"Stub flips to live with an env change, no code edit","done":false},{"text":"API failure falls back to the stub with a visible notice","done":false}]'::jsonb, 4, 3, 2, 2, 'groomed', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('33b812e9-8bed-0ae4-7f90-ebdc8082e7cc', 'As a daily user, I want a skippable sixty-second morning check-in showing my top three with one-tap status actions and a quick-capture for anything new, so that the day starts aligned without the app becoming a nag.', 'One sheet on the first open of the day: the top three ranked items with Start / Done / Park, plus a single capture field. Skipping is a first-class outcome, not a failure state.', '[{"text":"Appears on first open of a calendar day only","done":false},{"text":"Dismiss requires one tap","done":false},{"text":"Completing or skipping both take under a minute","done":false},{"text":"No punishment mechanics for skipped days","done":false}]'::jsonb, 4, 2, 2, 3, 'groomed', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('c9508117-ed83-12ca-5e61-69a7ba08a54f', 'As a daily user, I want to hand-order items with equal scores so that ties reflect my judgment instead of creation date.', 'Cut from v1. Only worth building if score ties turn out to be common in real use; revisit after a few weeks of dogfooding.', '[{"text":"Tied items expose a nudge-up and nudge-down control","done":false},{"text":"Manual order survives re-scoring while the tie holds","done":false}]'::jsonb, 2, 1, 1, 3, 'backlog', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
