insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('98aa9a53-2dfb-d6dc-cba5-8c898e76898b', 'Export the backlog as markdown for status updates', '', '[]'::jsonb, 3, 3, 3, 3, 'backlog', true, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('ed2b48dc-cfcd-e9ef-9a35-f98292b9c68a', 'As a returning user, I want an account with sync so that Foreground follows me across devices.', 'Supabase auth on the existing data layer. The v1 schema already carries RLS with a marked lockdown point.', '[{"text":"Sign in once per device; data follows the account","done":false},{"text":"RLS restricts every table to the owning user","done":false},{"text":"Existing local data migrates on first sign-in","done":false}]'::jsonb, 3, 1, 3, 8, 'later', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('beff802a-79a4-9658-72fd-28330999045e', 'As a working PM, I want my Asana projects imported so that Foreground ranks my real workload instead of a copy.', 'The item model has mirrored Asana task fields since v1 for exactly this. Import first; two-way sync is a separate, harder story.', '[{"text":"One-time import maps projects, tasks, sections, and due dates","done":false},{"text":"Re-import updates without duplicating","done":false}]'::jsonb, 4, 1, 2, 8, 'later', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('a35ac26c-107a-789f-350d-c0905777fe06', 'As a daily user, I want the full trail of touch notes on an item so that I can reconstruct where a slow-moving thing stands.', 'v1 keeps only the latest note by design. A history table is the clean later addition it was logged as.', '[{"text":"Every touch appends to a visible timeline on the item","done":false},{"text":"The latest note keeps its current placement in lists","done":false}]'::jsonb, 2, 1, 1, 3, 'later', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('770f1ffa-f99c-5b23-6a79-bbf794a9927b', 'As a daily user, I want one gentle daily notification when something is overdue or about to be so that I open the app at the right moment.', 'A single digest-style nudge, never per-item pings. Pairs with the morning check-in.', '[{"text":"At most one notification per day, at a chosen time","done":false},{"text":"Fires only when something is overdue or due within 48 hours","done":false},{"text":"One tap disables it for good","done":false}]'::jsonb, 3, 2, 1, 5, 'later', false, (now() - interval '0 days'));
insert into stories (id, title, description, acceptance_criteria, business_value, time_criticality, enablement, job_size, status, raw, created_at) values
  ('d22390c0-8238-11c9-4c51-f5a6a45471a9', 'As a phone user, I want Foreground installable and usable offline so that capture never waits for signal.', 'PWA manifest plus a service worker over the existing local-first data layer.', '[{"text":"Installable from the browser with the Foreground icon","done":false},{"text":"Capture and ranking work with no connection","done":false}]'::jsonb, 3, 1, 2, 3, 'later', false, (now() - interval '0 days'));
